mapper.select:
SELECT 
FROM notification
WHERE user_id = #{userId}

    AND is_read = #{isRead}

ORDER BY created_at DESC

mapper.update:
UPDATE notification SET is_read = 1
WHERE user_id = #{userId}
  AND is_read = 0

mapper.select:
SELECT COUNT(*) FROM notification
WHERE user_id = #{userId} AND type = 'REPORT'
  AND report_year = #{year} AND report_month = #{month}

SELECT MAX(threshold)
FROM notification
WHERE weekly_budget_id = #{weeklyBudgetId}
